entry.content:
问题描述 公司有n个员工，编号为1~n。 员工上班时登陆管理系统登记一个code，离开时进行注销。 管理人员随时想知道多少员工上班以及任一个员工登记的code。 输入输出 第一行是两个整数n,m。接下来是m行，每行是以下内容之一： I a c // Log In：员工 a 登录，code 为 c。若 a 已登录，则将 code 更新为 c O a // Log Out：编号为 a 的员工注销。若 a 未登录，则注销无效 C // Close：到下班时间，所有员工注销 N // Number：询问有多少员工正在上班 Q a // Query：询问员工 a 的 code（若未登录或已注销，视为 -1） 输入输出举例： 12345678910111213input:10 8I 1 2I 1 4Q 1CI 2 4O 2Q 2Noutput:3 # 输出为所有答案之和//“Q 1” 答案是 4，“Q 2” 答案是 -1，“N” 答案是 0，所有答案之和为 3 限制 n &lt;= 10,000,000 m &lt;= 1,000,000 1 &lt;= a &lt;= n code 为 [0, 2^31) 的整数 提示 一级提示 测试数据中，每种操作都可能频繁出现，或很少出现。因此，你的算法需要应对所有可能的情况。 答案会超出 int 范围，要注意各种数据类型可表示的范围，尤其是溢出问题。可选用 long long int 或 int64_t 等类型。注意各种数据类型的正确输入、输出方式。 Bitmap / 常数时间初始化的数组——讲义 02XA Bitmap: 习题解析 [2-34] 二级提示 避免频繁初始化整个数组。 可以借助Bitmap记录数组的各元素是否已被初始化。将一个（或所有）元素置为未初始化状态，实质上只需要打破“校验环”两个验证条件中的任何一个，考虑如何打破校验条件的复杂度最低。 另一种解题思路是，数组初始化 1 次后，记录改变了的元素，今后不再初始化整个数组，只初始化改变了的元素。 用 scanf(&quot;%c&quot;, ...) 或 getchar() 读入一个字符时，可能会读到空格、制表符、回车符或换行符，尽量避免使用这个方法。使用 scanf(&quot;%s&quot;, ...) 会自动过滤空白字符。 Windows 和 Linux 上换行符有 &quot;
&quot; 跟 &quot;
&quot; 的差别，你的程序最好有一定鲁棒性，能处理两种情况。 思路 先实现低效版，再思考改进。 低效版 先写一个低效版。其中通过while (isspace(op)) scanf(&quot;%c&quot;, &amp;op);来滤去空格以及换行制表等符号。 算法低效之处主要在于close()函数，当下班时只能对所有的元素进行赋值-1，而不能仅仅只针对已上班的员工。其他的主要函数时间复杂度都是O(1). 总的时间复杂度为O(n)，空间复杂都为O(n) 除了9,10,19测试点超时，其余测试点均可以通过。 将此算法生成的执行文件作为对拍的标准程序。 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465// 低效版// std_company.cpp#include&lt;iostream&gt;#include&lt;cstring&gt;using namespace std;class Company &#123; int num, N; long long int score; int* code;public: Company(int n) &#123; N = n; code = new int[N + 1]; for (int i = 0; i &lt; N + 1; i++) code[i] = -1; num = 0; score = 0; &#125; ~Company() &#123; delete[] code; &#125; void log_in(int a, int c) &#123; if (code[a] == -1) num++; code[a] = c; &#125; void log_out(int a) &#123; if (code[a] != -1) &#123; code[a] = -1; num--; &#125; &#125; void close() &#123; for (int i = 0; i &lt; N + 1; i++) code[i] = -1; num = 0; &#125; void number() &#123; score += num; &#125; void query(int a) &#123; score += code[a]; &#125; void show_ans() &#123; printf("%lld
", score); &#125;&#125;;int main() &#123; int n, m; scanf("%d%d", &amp;n, &amp;m); Company mycp(n); while (m--) &#123; char op; int a, c; scanf("%c", &amp;op); while (isspace(op)) scanf("%c", &amp;op); switch (op) &#123; case 'I': scanf("%d%d", &amp;a, &amp;c); mycp.log_in(a, c); break; case 'O': scanf("%d", &amp;a); mycp.log_out(a); break; case 'C': mycp.close(); break; case 'N': mycp.number(); break; case 'Q': scanf("%d", &amp;a); mycp.query(a); break; default: break; &#125; &#125; mycp.show_ans(); return 0;&#125; 思考改进 考虑加上习题解析[2-34]中bitmap的思路 采用同时支持set() clear()这两样操作的类，参考代码x2.9。 可以在O(1)时间隐式初始化（但是还有至少要有O(n)的分配内存的时间的） 查上班人数时还是沿用低效版的思路，用一个变量表示上班人数，log_in时加一，log_out时减一，都下班时清零。 仿照bitmap设置两个向量，F[]来记录[k]被标记的次序，向量T[]来记录依次被标记的值。 clear()时的改进：只需将top置零，时间复杂度O(1) 同时，code[]也不用全部初始化，只需每次修改code[F[k]]即可 如此，所有的操作时间复杂度都是O(1) 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677787980818283#include&lt;iostream&gt;#include&lt;cstring&gt;using namespace std;class Company &#123; int num, N; long long int score; int* code; int* F; int* T; int top;protected: bool valid(int r) &#123;return (0&lt;=r)&amp;&amp;(r&lt;top);&#125; bool erased(int a) &#123; return valid(F[a])&amp;&amp;!(T[F[a]]+1+a); // 删除时T[F[a]] = -1-a &#125;public: Company(int n) &#123; N = n; code = new int[N + 1]; F = new int[N + 1]; T = new int[N + 1]; top = 0; num = 0; score = 0; &#125; ~Company() &#123; delete[] code; delete[] F; delete[] T; &#125; bool test(int a)&#123; return valid(F[a]) &amp;&amp; (a==T[F[a]]); &#125; /* 登陆需要考虑： 1.从未登陆过 2.登陆过又再次登陆 3.登陆后进行注销后又再次登陆 */ void log_in(int a, int c) &#123; if(!test(a))&#123; // 测试不对，说明注销过或者从未登陆 if(!erased(a)) // 从未登陆过 F[a] = top++; // 创建新的校验环 num++; // 登陆人数加一 T[F[a]] = a; // 若注销过则需恢复原校验环 &#125; code[F[a]] = c; &#125; void log_out(int a) &#123; if(test(a)) &#123; // 已登陆 T[F[a]] = -1-a; num--; // 登陆人数减一 &#125; &#125; void close() &#123; top = 0; // 直接 top 置零，和低效版相比有所改进 num = 0; &#125; void number() &#123; score += num; &#125; void query(int a) &#123; if(test(a)) score += code[F[a]]; else score += -1; &#125; void show_ans() &#123; printf("%lld
", score); &#125;&#125;;int main() &#123; int n, m; scanf("%d%d", &amp;n, &amp;m); Company mycp(n); while (m--) &#123; char op; int a, c; scanf("%c", &amp;op); while (isspace(op)) scanf("%c", &amp;op); switch (op) &#123; case 'I': scanf("%d%d", &amp;a, &amp;c); mycp.log_in(a, c); break; case 'O': scanf("%d", &amp;a); mycp.log_out(a); break; case 'C': mycp.close(); break; case 'N': mycp.number(); break; case 'Q': scanf("%d", &amp;a); mycp.query(a); break; default: break; &#125; &#125; mycp.show_ans(); return 0;&#125;
